import React, {useMemo,} from 'react';
import {GestureResponderEvent, ScrollView, TouchableOpacity, View} from 'react-native';
import Animated from 'react-native-reanimated';
import type {IResponsiveElement} from '@lmb-it/kitsconcerto-types';
import {
  Box,
  Button,
  ButtonGroup,
  Card,
  Center,
  Grid,
  GridItem,
  Heading,
  HStack,
  Image,
  Pressable,
  Skeleton,
  Text,
  VStack
} from '@lmb-it/kitsconcertomobile';
import {style} from './helpers/style';
import {useStyleContext} from './DimensionsContext';
import {enteringPresets, exitingPresets} from './animationPresets';


const COMPONENT_MAP: Record<string, React.ElementType<any>> = {
  Button: Button,
  ButtonGroup: ButtonGroup,
  Svg: View,
  List: View,
  ListItem: View,
  a: Pressable,
  Pressable: Pressable,
  Box,
  Image,
  Grid,
  GridItem,
  Card,
  Text,
  Heading,
  Center,
  Skeleton,
  HStack, VStack,
  ScrollView: ScrollView,
};



const ResponsiveElement = <T,>({
                                 additionalStyles = {},
                                 additionalClasses, // ignored in native
                                 nativeProps,
                                 cssProps,
                                 children,
                                 as,
                                 scrollable,
                                 entering,
                                 exiting,
                                 ref, // directly available in React 19+
                               }: React.PropsWithChildren<IResponsiveElement<T>> & { ref?: React.Ref<any> }) => {

  const styleCtx = useStyleContext();
  const combinedStyles = useMemo(() => {
    return [style({ ...additionalStyles,...cssProps, ...nativeProps?.style }, styleCtx)];
  }, [cssProps, additionalStyles, nativeProps?.style, styleCtx]);

  const Component = as
    ? COMPONENT_MAP[as] || View
    : View;



  const isText = (typeof children === 'string' || typeof children === 'number') && (as !== 'Heading' && as !== 'Text')

  const hasAnimation = !!(entering || exiting);

  // Read animation duration/delay from cssProps (they flow through useSeparator)
  const animationDuration = cssProps?.animationDuration as number | undefined;
  const animationDelay = cssProps?.animationDelay as number | undefined;

  const enteringAnim = useMemo(() => {
    if (!entering) return undefined;
    let anim: any = enteringPresets[entering];
    if (animationDuration != null) anim = anim.duration(animationDuration);
    if (animationDelay != null) anim = anim.delay(animationDelay);
    return anim;
  }, [entering, animationDuration, animationDelay]);

  const exitingAnim = useMemo(() => {
    if (!exiting) return undefined;
    let anim: any = exitingPresets[exiting];
    if (animationDuration != null) anim = anim.duration(animationDuration);
    if (animationDelay != null) anim = anim.delay(animationDelay);
    return anim;
  }, [exiting, animationDuration, animationDelay]);

  /* ---- Press handling for non-Button components ---- */
  const pressHandler = ('onClick' in nativeProps ? nativeProps?.onClick : 'onPress' in nativeProps ? nativeProps?.onPress : null) as ((event: GestureResponderEvent) => void) | null;
  const hasPressHandler = typeof pressHandler === 'function';
  const isButton = as === 'Button' || as === 'ButtonGroup';
  const isImage = as === 'Image';

  // Strip onClick/onPress from nativeProps — View/Image don't support them
  const cleanedNativeProps = useMemo(() => {
    if (!hasPressHandler || isButton) return nativeProps;
    if (!nativeProps) return nativeProps;
    const {onClick, onPress, ...rest} = nativeProps as any;
    return rest;
  }, [nativeProps, hasPressHandler, isButton]);

  const touchFill = {width: '100%' as const, height: '100%' as const};

  let content: React.ReactElement;

  if (hasPressHandler && pressHandler && !isButton) {
    if (isImage) {
      // Image: wrap externally so the whole image area is tappable
      content = (
          <TouchableOpacity activeOpacity={0.7} onPress={pressHandler}>
            <Component ref={ref} {...cleanedNativeProps} style={combinedStyles} className={additionalClasses}/>
          </TouchableOpacity>
      );
    } else {
      // Box, VStack, HStack, Center, Text, etc.: inject TouchableOpacity as child
      content = (
          <TouchableOpacity activeOpacity={0.7} onPress={pressHandler} style={combinedStyles}>
            <Component ref={ref} {...cleanedNativeProps} style={{...combinedStyles,borderWidth:0}} className={additionalClasses}>
              {isText ? <Text>{children}</Text> : children}
            </Component>
          </TouchableOpacity>
      );
    }
  } else {
    content = (
        <Component ref={ref} {...nativeProps} style={combinedStyles} className={additionalClasses}>
          {isText ? <Text>{children}</Text> : children}
        </Component>
    );
  }

  if (scrollable) {
    return <ScrollView horizontal={as === 'HStack'}>{content}</ScrollView>;
  }

  if (hasAnimation) {
    return (
      <Animated.View entering={enteringAnim} exiting={exitingAnim}>
        {content}
      </Animated.View>
    );
  }

  return content;
}

export default ResponsiveElement;
